create table if not exists pulse_settings(id bigserial primary key,month_target integer not null default 150000,period_start date not null default date_trunc('month', now())::date,period_end date not null default (date_trunc('month', now()) + interval '1 month - 1 day')::date,rest_weekdays integer[] not null default '{2}',created_at timestamptz default now());
create table if not exists pulse_income_entries(id bigserial primary key,entry_date date not null default (now() at time zone 'Asia/Taipei')::date,client_id uuid null,client_name_snapshot text,service_code text,service_line text,service_name text,service_variant text,standard_price integer,amount_actual integer,amount integer,source text,note text,created_at timestamptz default now());
create table if not exists pulse_appointments(id bigserial primary key,appointment_date date not null default (now() at time zone 'Asia/Taipei')::date,start_time time,client_id uuid null,client_name_snapshot text,service_code text,service_line text,service_name text,service_variant text,standard_price integer,estimated_amount integer,status text default '待確認',note text,created_at timestamptz default now());
create table if not exists pulse_followups(id bigserial primary key,client_id uuid null,client_name_snapshot text,last_visit_date date,reason text,contact_method text,priority text default '中',status text default '未聯絡',note text,created_at timestamptz default now());
insert into pulse_settings(month_target) select 150000 where not exists(select 1 from pulse_settings);
